type Tag = string;
type EntityTagFactory = (_id: string | number) => Tag;
type TagRegistry = Record<string, Tag | EntityTagFactory>;

export const CACHE_TAGS = {
  departments: "table:departments",
  employees: "table:employees",
  machines: "table:machines",
  dailyLogs: "table:daily_logs",
  machineOperations: "table:machine_operations",
  hourlyLoads: "table:hourly_loads",
  operationalDelays: "table:operational_delays",
  excavatorActivity: "table:excavator_activity",
  dozerRolls: "table:dozer_rolls",
  drillOperations: "table:drill_operations",
  productionLogs: "table:production_logs",
  fuelLogs: "table:fuel_logs",
  shiftStatus: "table:shift_status",
  safetyIncidents: "table:safety_incidents",
  sites: "table:sites",
  badges: "table:badges",
  accessLogs: "table:access_logs",
  visitors: "table:visitors",
  breakdowns: "table:breakdowns",
  delayCategories: "table:delay_categories",
  engineeringNotes: "table:engineering_notes",
  tireManagement: "table:tire_management",
  certifications: "table:certifications",
  courses: "table:courses",
  machineHours: "table:machine_hours",
  operators: "table:operators",
  weather: "weather",
  hub: "hub",

  employee: ((id) => `employee:${id}`) satisfies EntityTagFactory,
  machine: ((id) => `machine:${id}`) satisfies EntityTagFactory,
  dailyLog: ((id) => `daily_log:${id}`) satisfies EntityTagFactory,
  safetyIncident: ((id) => `safety_incident:${id}`) satisfies EntityTagFactory,
  shiftStatusEntry: ((id) => `shift_status:${id}`) satisfies EntityTagFactory,
} as const satisfies TagRegistry;
